import{_ as t,o as a,c as l,ae as i}from"./chunks/framework.BAOUhEwF.js";const m=JSON.parse('{"title":"elements/form/datalist","description":"","frontmatter":{},"headers":[],"relativePath":"api/ts/elements/form/datalist/README.md","filePath":"api/ts/elements/form/datalist/README.md"}'),s={name:"api/ts/elements/form/datalist/README.md"};function o(n,e,r,d,c,u){return a(),l("div",null,[...e[0]||(e[0]=[i('<p><a href="./../../../README.html"><strong>@vastare/fundatio v0.1.0</strong></a></p><hr><h1 id="elements-form-datalist" tabindex="-1">elements/form/datalist <a class="header-anchor" href="#elements-form-datalist" aria-label="Permalink to &quot;elements/form/datalist&quot;">​</a></h1><p>Fundatio Design Foundation: Datalist element helpers.</p><h2 id="remarks" tabindex="-1">Remarks <a class="header-anchor" href="#remarks" aria-label="Permalink to &quot;Remarks&quot;">​</a></h2><p>The datalist element (<code>&lt;datalist&gt;</code>) contains a set of <code>&lt;option&gt;</code> elements that represent permissible or recommended values for an associated form control (most commonly an <code>&lt;input&gt;</code>), connected via the input&#39;s <code>list</code> attribute.</p><p>Best-practice guidance:</p><ul><li>Pair a <code>&lt;datalist&gt;</code> with an <code>&lt;input&gt;</code> using a stable, unique <code>id</code> on the datalist and a matching <code>list</code> attribute on the input.</li><li>Use <code>&lt;datalist&gt;</code> for suggestions, not strict validation. If users must pick from a fixed set, prefer <code>&lt;select&gt;</code>.</li><li>Populate suggestions using descendant <code>&lt;option&gt;</code> elements, typically with <code>value</code> attributes.</li></ul><p>This module provides small, framework-agnostic helpers so consumers can:</p><ul><li>create <code>&lt;datalist&gt;</code> elements in vanilla JS/TS without templates</li><li>apply consistent global attributes safely</li><li>use a stable &quot;enhancement&quot; hook if Fundatio ever needs runtime behavior</li></ul><p>This module has no side effects and does not mutate the DOM unless you call its functions.</p><p>Attributes:</p><ul><li><code>&lt;datalist&gt;</code> supports global attributes only (no element-specific content attributes).</li></ul><p>Security:</p><ul><li>Global attribute escape hatches are guarded by Fundatio&#39;s <code>dom.ts</code> helpers which block inline event handler attributes (e.g. <code>onclick</code>) and raw <code>style</code> attribute injection (use the <code>style</code> object field instead).</li></ul><h2 id="see" tabindex="-1">See <a class="header-anchor" href="#see" aria-label="Permalink to &quot;See&quot;">​</a></h2><p><a href="https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Elements/datalist" target="_blank" rel="noreferrer">https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Elements/datalist</a></p><h2 id="type-aliases" tabindex="-1">Type Aliases <a class="header-anchor" href="#type-aliases" aria-label="Permalink to &quot;Type Aliases&quot;">​</a></h2><h3 id="attributes" tabindex="-1">Attributes <a class="header-anchor" href="#attributes" aria-label="Permalink to &quot;Attributes&quot;">​</a></h3><ul><li><a href="./type-aliases/DatalistAttrs.html">DatalistAttrs</a></li><li><a href="./type-aliases/StructuredAria.html">StructuredAria</a></li></ul><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h2><h3 id="constants" tabindex="-1">Constants <a class="header-anchor" href="#constants" aria-label="Permalink to &quot;Constants&quot;">​</a></h3><ul><li><a href="./variables/DATALIST_SELECTOR.html">DATALIST_SELECTOR</a></li><li><a href="./variables/DATALIST_TAG.html">DATALIST_TAG</a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="dom" tabindex="-1">DOM <a class="header-anchor" href="#dom" aria-label="Permalink to &quot;DOM&quot;">​</a></h3><ul><li><a href="./functions/createDatalist.html">createDatalist</a></li></ul><h3 id="enhancement" tabindex="-1">Enhancement <a class="header-anchor" href="#enhancement" aria-label="Permalink to &quot;Enhancement&quot;">​</a></h3><ul><li><a href="./functions/enhanceDatalists.html">enhanceDatalists</a></li></ul>',28)])])}const p=t(s,[["render",o]]);export{m as __pageData,p as default};
